import { useState, useEffect } from 'react'
import { Tree, Spin, Empty, message } from 'antd'
import { FileOutlined, FolderOutlined } from '@ant-design/icons'
import type { DataNode } from 'antd/es/tree'

// 浏览器环境下替代 path.join 的工具函数
const pathJoin = (...parts: string[]): string => {
  return parts.filter(Boolean).join('/')
}

interface OutlineTreeProps {
  projectRoot: string
  activeChapter: string | null
  onSelect: (filePath: string) => void
}

interface FileEntry {
  name: string
  isDirectory: boolean
  isFile: boolean
  path: string
  children?: FileEntry[]
}

const OutlineTree = ({ projectRoot, activeChapter, onSelect }: OutlineTreeProps) => {
  const [treeData, setTreeData] = useState<DataNode[]>([])
  const [loading, setLoading] = useState(false)
  const [expandedKeys, setExpandedKeys] = useState<React.Key[]>([])

  // 读取目录结构
  const loadDirectory = async (dirPath: string): Promise<FileEntry[]> => {
    try {
      const entries = await window.electronAPI.readdir(dirPath)
      if (!Array.isArray(entries)) return []

      const result: FileEntry[] = []

      for (const entry of entries) {
        const fullPath = pathJoin(dirPath, entry.name)

        if (entry.isDirectory) {
          const children = await loadDirectory(fullPath)
          result.push({
            name: entry.name,
            isDirectory: true,
            isFile: false,
            path: fullPath,
            children
          })
        } else if (entry.isFile && entry.name.endsWith('.md')) {
          result.push({
            name: entry.name.replace('.md', ''),
            isDirectory: false,
            isFile: true,
            path: fullPath
          })
        }
      }

      return result.sort((a, b) => {
        if (a.isDirectory && !b.isDirectory) return -1
        if (!a.isDirectory && b.isDirectory) return 1
        return a.name.localeCompare(b.name)
      })
    } catch (error) {
      console.error('读取目录失败:', error)
      return []
    }
  }

  // 转换为 Ant Design Tree 需要的格式
  const convertToTreeData = (entries: FileEntry[], parentKey: string = ''): DataNode[] => {
    return entries.map((entry, index) => {
      const key = entry.path  // 统一用真实路径作为 key，保证选中高亮正确

      if (entry.isDirectory && entry.children) {
        return {
          title: entry.name,
          key,
          icon: <FolderOutlined />,
          children: convertToTreeData(entry.children, key),
          isLeaf: false
        }
      } else {
        return {
          title: entry.name,
          key,
          icon: <FileOutlined />,
          isLeaf: true
        }
      }
    })
  }

  // 加载大纲
  useEffect(() => {
    const loadOutline = async () => {
      if (!projectRoot) return

      setLoading(true)
      try {
        const plotsDir = pathJoin(projectRoot, 'plots')
        const existsResult = await window.electronAPI.exists(plotsDir)
        if (!existsResult || !existsResult.success || !existsResult.exists) {
          await window.electronAPI.mkdir(plotsDir)
          setTreeData([])
          return
        }

        const entries = await loadDirectory(plotsDir)
        const data = convertToTreeData(entries)
        setTreeData(data)

        const getAllKeys = (nodes: DataNode[]): string[] => {
          let keys: string[] = []
          nodes.forEach(node => {
            keys.push(node.key as string)
            if (node.children) keys = keys.concat(getAllKeys(node.children))
          })
          return keys
        }
        setExpandedKeys(getAllKeys(data))
      } catch (error) {
        message.error('加载大纲失败')
        console.error(error)
      } finally {
        setLoading(false)
      }
    }

    loadOutline()
  }, [projectRoot])

  // 监听文件变化，自动刷新大纲
  useEffect(() => {
    if (!projectRoot) return

    const plotsDir = pathJoin(projectRoot, 'plots')
    window.electronAPI.fsWatch(plotsDir)

    const removeListener = window.electronAPI.onFsChange(() => {
      loadDirectory(pathJoin(projectRoot, 'plots')).then(entries => {
        const data = convertToTreeData(entries)
        setTreeData(data)
      })
    })

    return () => {
      removeListener()
      window.electronAPI.fsUnwatch()
    }
  }, [projectRoot])

  // 处理选择
  const handleSelect = (selectedKeys: React.Key[]) => {
    if (selectedKeys.length === 0) return
    const key = String(selectedKeys[0])
    if (key.startsWith('/') || key.includes('.md')) {
      onSelect(key)
    }
  }

  if (loading) {
    return (
      <div style={{ padding: 20, textAlign: 'center' }}>
        <Spin tip="加载中..." />
      </div>
    )
  }

  if (treeData.length === 0) {
    return (
      <div style={{ padding: 20 }}>
        <Empty
          description="暂无章节"
          image={Empty.PRESENTED_IMAGE_SIMPLE}
        />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', overflow: 'auto', padding: 10 }}>
      <Tree
        treeData={treeData}
        expandedKeys={expandedKeys}
        selectedKeys={activeChapter ? [activeChapter] : []}
        onSelect={handleSelect}
        onExpand={setExpandedKeys}
        showIcon
        defaultExpandAll
      />
    </div>
  )
}

export default OutlineTree

/**
 * 人物关系图可视化
 * 使用 graphology 实现力导向图
 * 节点：人物，边：人物关系
 * 支持点击查看详情
 */

import { useEffect, useRef, useState, useCallback } from 'react'
import { Card, Button, Space, message, Spin, Drawer, Descriptions, Tag } from 'antd'
import { ReloadOutlined } from '@ant-design/icons'
import Graph from 'graphology'
import forceAtlas2 from 'graphology-layout-forceatlas2'

interface GraphNode {
  id: string
  label: string
  mbti?: string
  type?: string
}

interface RawRelationship {
  from: string
  to: string
  type: string
  strength: number
  development?: unknown[]
}

interface GraphEdge {
  id: string
  source: string
  target: string
  label: string
  weight: number
  from: string
  to: string
  type: string
  strength: number
}

interface CharacterGraphProps {
  projectRoot: string | null
  onNodeClick?: (characterName: string) => void
}

const REL_TYPE_COLORS: Record<string, string> = {
  mentor: '#1677ff',
  rival: '#ff4d4f',
  love: '#eb2f96',
  family: '#52c41a',
  friend: '#13c2c2',
  master: '#722ed1',
  enemy: '#d4380d',
}

const CharacterGraph: React.FC<CharacterGraphProps> = ({ projectRoot }) => {
  const [loading, setLoading] = useState(false)
  const [graphData, setGraphData] = useState<{
    nodes: GraphNode[]
    edges: GraphEdge[]
  } | null>(null)
  const [selectedNode, setSelectedNode] = useState<GraphNode | null>(null)
  const [drawerVisible, setDrawerVisible] = useState(false)

  const loadGraphData = useCallback(async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      // 读取 relationships.yaml
      const relFile = `${projectRoot}/relationships.yaml`
      const relResult = await window.electronAPI.yaml.read(relFile)
      const relData = relResult.success
        ? (relResult.data as Record<string, unknown>)
        : { relationships: [] }
      const rels = (relData.relationships as RawRelationship[]) || []

      // 读取角色基本信息
      const charsDir = `${projectRoot}/characters`
      const charFilesResult = await window.electronAPI.readdir(charsDir)
      if (!charFilesResult.success) { console.error('读取characters目录失败:', charFilesResult.error); }
      const charFiles = charFilesResult.data || []
      const charInfoMap: Record<string, GraphNode> = {}

      for (const file of charFiles) {
        if (file.isFile && file.name.endsWith('.yaml')) {
          const charResult = await window.electronAPI.yaml.read(`${charsDir}/${file.name}`)
          if (charResult.success && charResult.data) {
            const data = charResult.data as Record<string, unknown>
            const name = String(data.name || file.name.replace('.yaml', ''))
            charInfoMap[name] = {
              id: name,
              label: name,
              mbti: data.mbti as string | undefined,
              type: 'character',
            }
          }
        }
      }

      // 构建节点（所有出现在关系中的角色）
      const nodeSet = new Set<string>()
      for (const rel of rels) {
        nodeSet.add(rel.from)
        nodeSet.add(rel.to)
      }

      const nodes: GraphNode[] = Array.from(nodeSet).map(name => {
        const info = charInfoMap[name] || {}
        return {
          id: name,
          label: name,
          mbti: info.mbti,
          type: info.type,
        }
      })

      const edges: GraphEdge[] = rels.map((rel: RawRelationship, idx: number) => ({
        id: `edge-${idx}`,
        source: String(rel.from || ''),
        target: String(rel.to || ''),
        from: String(rel.from || ''),
        to: String(rel.to || ''),
        label: String(rel.type || ''),
        type: String(rel.type || ''),
        weight: (rel.strength as number) || 0.5,
        strength: (rel.strength as number) || 0.5,
      }))

      setGraphData({ nodes, edges })
    } catch (error) {
      console.error('加载关系图失败:', error)
      message.error('加载关系图失败')
    } finally {
      setLoading(false)
    }
  }, [projectRoot])

  useEffect(() => {
    loadGraphData()
  }, [loadGraphData])

  const handleNodeClick = useCallback((nodeId: string) => {
    setSelectedNode(prev => graphData?.nodes.find(n => n.id === nodeId) || prev)
    setDrawerVisible(true)
  }, [graphData])

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  if (loading) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Spin tip="加载关系图..." />
      </div>
    )
  }

  if (!graphData || graphData.nodes.length === 0) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <div style={{ color: '#999', marginBottom: 16 }}>
          暂无人物关系数据
        </div>
        <Button icon={<ReloadOutlined />} onClick={loadGraphData}>
          刷新
        </Button>
      </div>
    )
  }

  // 简单的 SVG 力导向图实现
  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div
        style={{
          padding: '8px 16px',
          borderBottom: '1px solid #e8e8e8',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
        }}
      >
        <span style={{ fontSize: 13 }}>
          人物关系图 · {graphData.nodes.length} 人 / {graphData.edges.length} 条关系
        </span>
        <Space>
          <Button size="small" icon={<ReloadOutlined />} onClick={loadGraphData}>
            刷新
          </Button>
        </Space>
      </div>

      <ForceGraph
        nodes={graphData.nodes}
        edges={graphData.edges}
        onNodeClick={handleNodeClick}
      />

      <Drawer
        title={selectedNode?.label}
        open={drawerVisible}
        onClose={() => setDrawerVisible(false)}
        width={300}
      >
        {selectedNode && (
          <Descriptions column={1} size="small">
            <Descriptions.Item label="名称">{selectedNode.label}</Descriptions.Item>
            {selectedNode.mbti && (
              <Descriptions.Item label="MBTI">
                <Tag color="purple">{selectedNode.mbti}</Tag>
              </Descriptions.Item>
            )}
            <Descriptions.Item label="相关关系">
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {graphData?.edges
                  .filter(e => e.source === selectedNode.id || e.target === selectedNode.id)
                  .map((edge, idx) => {
                    const other = edge.source === selectedNode.id ? edge.target : edge.source
                    return (
                      <Tag
                        key={idx}
                        color={REL_TYPE_COLORS[edge.label] || 'default'}
                      >
                        {other} ({edge.label})
                      </Tag>
                    )
                  })}
              </div>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Drawer>
    </div>
  )
}

// 简单的 SVG 力导向图组件
interface ForceGraphProps {
  nodes: GraphNode[]
  edges: GraphEdge[]
  onNodeClick: (nodeId: string) => void
}

const ForceGraph: React.FC<ForceGraphProps> = ({ nodes, edges, onNodeClick }) => {
  const containerRef = useRef<HTMLDivElement>(null)
  const [positions, setPositions] = useState<Record<string, { x: number; y: number }>>({})
  const [dragging, setDragging] = useState<string | null>(null)

  // 初始化力导向布局
  useEffect(() => {
    if (nodes.length === 0) return

    const graph = new Graph()

    // 添加节点
    for (const node of nodes) {
      graph.addNode(node.id, {
        label: node.label,
        x: Math.random() * 400 + 100,
        y: Math.random() * 300 + 100,
        size: 20,
        color: '#1890ff',
      })
    }

    // 添加边
    for (const edge of edges) {
      if (graph.hasNode(edge.source) && graph.hasNode(edge.target)) {
        try {
          graph.addEdge(edge.source, edge.target, {
            label: edge.label,
            size: edge.weight * 3 + 1,
            color: REL_TYPE_COLORS[edge.label] || '#999',
          })
        } catch {
          // 边已存在则跳过
        }
      }
    }

    // 运行 ForceAtlas2
    if (graph.order > 0) {
      try {
        forceAtlas2.assign(graph, {
          iterations: 100,
          settings: {
            gravity: 1,
            scalingRatio: 10,
            strongGravityMode: true,
          },
        })
      } catch (e) {
        console.warn('ForceAtlas2 布局失败，使用随机位置:', e)
      }
    }

    // 提取位置
    const pos: Record<string, { x: number; y: number }> = {}
    graph.forEachNode((nodeId, attrs) => {
      pos[nodeId] = { x: (attrs.x as number) || 0, y: (attrs.y as number) || 0 }
    })

    setPositions(pos)
  }, [nodes, edges])

  if (nodes.length === 0) return null

  // 计算 bounds
  const posValues = Object.values(positions)
  if (posValues.length === 0) return null

  const minX = Math.min(...posValues.map(p => p.x))
  const maxX = Math.max(...posValues.map(p => p.x))
  const minY = Math.min(...posValues.map(p => p.y))
  const maxY = Math.max(...posValues.map(p => p.y))
  const rangeX = maxX - minX || 1
  const rangeY = maxY - minY || 1

  const width = 500
  const height = 400
  const padding = 40
  const scaleX = (width - 2 * padding) / rangeX
  const scaleY = (height - 2 * padding) / rangeY

  const getX = (x: number) => (x - minX) * scaleX + padding
  const getY = (y: number) => (y - minY) * scaleY + padding

  return (
    <div
      ref={containerRef}
      style={{ flex: 1, overflow: 'auto', background: '#fafafa' }}
    >
      <svg width={width} height={height} style={{ cursor: 'grab' }}>
        {/* 绘制边 */}
        {edges.map(edge => {
          const fromPos = positions[edge.source]
          const toPos = positions[edge.target]
          if (!fromPos || !toPos) return null

          const x1 = getX(fromPos.x)
          const y1 = getY(fromPos.y)
          const x2 = getX(toPos.x)
          const y2 = getY(toPos.y)

          // 计算边的中点（用于放置标签）
          const midX = (x1 + x2) / 2
          const midY = (y1 + y2) / 2

          return (
            <g key={edge.id}>
              <line
                x1={x1}
                y1={y1}
                x2={x2}
                y2={y2}
                stroke={REL_TYPE_COLORS[edge.label] || '#999'}
                strokeWidth={Math.max(edge.weight * 3 + 1, 1)}
                strokeOpacity={0.6}
              />
              <text
                x={midX}
                y={midY - 5}
                textAnchor="middle"
                fontSize={10}
                fill={REL_TYPE_COLORS[edge.label] || '#999'}
                style={{ pointerEvents: 'none' }}
              >
                {edge.label}
              </text>
            </g>
          )
        })}

        {/* 绘制节点 */}
        {nodes.map(node => {
          const pos = positions[node.id]
          if (!pos) return null

          const cx = getX(pos.x)
          const cy = getY(pos.y)

          return (
            <g
              key={node.id}
              style={{ cursor: 'pointer' }}
              onClick={() => onNodeClick(node.id)}
            >
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill="#1890ff"
                stroke="#fff"
                strokeWidth={2}
              />
              <text
                x={cx}
                y={cy + 4}
                textAnchor="middle"
                fontSize={11}
                fill="#fff"
                style={{ pointerEvents: 'none', fontWeight: 'bold' }}
              >
                {node.label.slice(0, 2)}
              </text>
              <text
                x={cx}
                y={cy - 22}
                textAnchor="middle"
                fontSize={11}
                fill="#333"
                style={{ pointerEvents: 'none' }}
              >
                {node.label}
              </text>
            </g>
          )
        })}
      </svg>

      {/* 图例 */}
      <div
        style={{
          padding: '8px 16px',
          fontSize: 11,
          color: '#666',
          borderTop: '1px solid #e8e8e8',
          display: 'flex',
          gap: 12,
          flexWrap: 'wrap',
        }}
      >
        {Object.entries(REL_TYPE_COLORS).map(([type, color]) => (
          <span key={type} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <span
              style={{
                display: 'inline-block',
                width: 16,
                height: 2,
                background: color,
              }}
            />
            {type}
          </span>
        ))}
      </div>
    </div>
  )
}

export default CharacterGraph

/**
 * AI 工具面板
 * 包含：智能续写、定向扩写、逻辑校验、提取事实、AI重写、AI润色、语法检查、大纲生成、风格迁移
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  Input,
  message,
  Spin,
  Modal,
  Select,
  Divider,
  Tabs,
  Alert,
  Radio,
  Slider,
} from 'antd'
import {
  EditOutlined,
  ExpandOutlined,
  CheckCircleOutlined,
  ThunderboltOutlined,
  SaveOutlined,
  SyncOutlined,
  BulbOutlined,
  BgColorsOutlined,
  ProfileOutlined,
  ScissorOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'
import factExtractor, { ExtractedFact } from '../services/factExtractor'

const { TextArea } = Input

interface AIToolsPanelProps {
  chapterContent: string
  chapterPath: string | null
  getSelectedText: () => string
  onInsertText: (text: string) => void
}

type RewriteMode = 'concise' | 'expand' | 'improve'
type RewriteScope = 'chapter' | 'paragraph'

const STYLE_OPTIONS = [
  { value: '金庸', label: '金庸（武侠古典）' },
  { value: '猫腻', label: '猫腻（文笔华丽）' },
  { value: '烽火戏诸侯', label: '烽火戏诸侯（热血燃系）' },
  { value: '乌山居', label: '乌山居（简洁流畅）' },
  { value: '辰东', label: '辰东（宏大壮阔）' },
  { value: '土豆', label: '土豆（小白文爽文）' },
  { value: '古龙', label: '古龙（简洁悬疑）' },
  { value: '鲁迅', label: '鲁迅（深刻犀利）' },
  { value: '海明威', label: '海明威（简洁有力）' },
]

const AIToolsPanel = ({ chapterContent, chapterPath, getSelectedText, onInsertText }: AIToolsPanelProps) => {
  const [generating, setGenerating] = useState(false)
  const [result, setResult] = useState('')
  const [prompt, setPrompt] = useState('')
  const [extractedFacts, setExtractedFacts] = useState<ExtractedFact[]>([])
  const [activeTool, setActiveTool] = useState<string>('continue')

  // 智能续写
  const handleContinue = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节并编写内容')
      return
    }
    setActiveTool('continue')
    setGenerating(true)
    setResult('')

    try {
      const context = chapterContent.slice(-800)
      const fullPrompt = `请继续写下面的小说内容，风格保持一致，衔接自然：

${context}

续写内容（请直接输出续写文本，不需要加标题）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`续写失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('续写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 定向扩写
  const handleExpand = async () => {
    if (!prompt) {
      message.warning('请输入扩写要求')
      return
    }
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('expand')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请根据以下要求扩写小说内容。要求：${prompt}

当前章节上下文：
${chapterContent.slice(-1200)}

扩写后的内容（请直接输出扩写文本）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`扩写失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('扩写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 逻辑校验
  const handleCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('check')
    setGenerating(true)
    setResult('')

    try {
      const checkResult = await aiModelService.call(
        'logic',
        chapterContent,
        {
          systemPrompt: `请检查以下小说章节内容的逻辑一致性，找出矛盾点、战力崩坏、情节不合理的地方，给出修改建议。请使用清晰的格式输出检查结果。`
        }
      )

      if (checkResult.success && checkResult.content) {
        setResult(checkResult.content)
      } else {
        message.error(checkResult.error || '校验失败')
      }
    } catch (error) {
      message.error('逻辑校验失败')
    } finally {
      setGenerating(false)
    }
  }

  // 提取事实
  const handleExtract = async () => {
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('extract')
    setGenerating(true)
    setResult('')

    try {
      const chapterMatch = chapterPath.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1

      const facts = await factExtractor.extract(chapterContent, chapterNumber)
      setExtractedFacts(facts)

      if (facts.length === 0) {
        setResult('未提取到任何事实')
        return
      }

      let output = `提取到 ${facts.length} 条事实：\n\n`
      facts.forEach((fact, index) => {
        output += `${index + 1}. [${fact.type}] ${fact.subject}${fact.object ? ' → ' + fact.object : ''}\n`
        output += `   ${fact.content} (置信度: ${(fact.confidence * 100).toFixed(0)}%)\n\n`
      })

      output += `\n点击「保存到台账」将以上事实追加写入 facts YAML 文件。`
      setResult(output)
    } catch (error) {
      message.error('事实提取失败')
    } finally {
      setGenerating(false)
    }
  }

  // 保存提取的事实到 facts 台账
  const handleSaveFacts = async () => {
    if (extractedFacts.length === 0) return
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setGenerating(true)
    try {
      const chapterMatch = chapterPath?.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1
      const saved = await factExtractor.extractAndSave(chapterContent, chapterNumber)
      if (saved.length > 0) {
        message.success(`已保存 ${saved.length} 条事实到台账`)
        setResult('')
        setExtractedFacts([])
      } else {
        message.error('保存失败')
      }
    } catch (error) {
      message.error('保存失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 重写（增强版）──────────────────────────────────────────────────────
  const [rewriteMode, setRewriteMode] = useState<RewriteMode>('improve')
  const [rewriteScope, setRewriteScope] = useState<RewriteScope>('chapter')
  const [rewritePromptText, setRewritePromptText] = useState('')

  const getRewritePromptForMode = (mode: RewriteMode): string => {
    const prompts: Record<RewriteMode, string> = {
      concise: '精简内容，去除冗余表达，使文字更加凝练有力',
      expand: '适度扩展细节描写，丰富场景和情感刻画',
      improve: '改善文笔和叙事节奏，提升整体可读性',
    }
    return prompts[mode]
  }

  const handleRewrite = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('rewrite')
    setGenerating(true)
    setResult('')

    try {
      const modeText = rewriteMode === 'concise' ? '精简' : rewriteMode === 'expand' ? '扩展' : '改进'
      let rewriteInstruction = getRewritePromptForMode(rewriteMode)
      if (rewritePromptText) {
        rewriteInstruction += `。额外要求：${rewritePromptText}`
      }

      if (rewriteScope === 'paragraph') {
        const selectedText = getSelectedText()
        if (!selectedText || selectedText.length < 10) {
          message.warning('请先在编辑器中选中要重写的段落（至少10个字）')
          setGenerating(false)
          return
        }
        const fullPrompt = `请重写以下小说段落，保持情节和主题不变，但使文笔更优美：

原文：
${selectedText}

重写模式：${modeText}
要求：${rewriteInstruction}

重写后的内容（直接输出原文对照，重写文本用【】包裹）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`重写失败：${error}`); setGenerating(false); }
        )
      } else {
        const fullPrompt = `请重写以下小说章节，保持情节和主题不变，但改善文笔和叙事：

原文：
${chapterContent.slice(-2000)}

重写模式：${modeText}
要求：${rewriteInstruction}

重写后的内容（直接输出，不要加标题或说明）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`重写失败：${error}`); setGenerating(false); }
        )
      }
    } catch (error) {
      message.error('重写失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 润色 ─────────────────────────────────────────────────────────────
  const handlePolish = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('polish')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请对以下小说内容进行文笔润色，改善表达流畅度、精简冗余、提升文字质感，但不改变原意和情节：

原文：
${chapterContent.slice(-1500)}

润色后的内容（直接输出，不要加说明）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`润色失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('润色失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 语法检查 ─────────────────────────────────────────────────────────────
  const handleGrammarCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('grammar')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请检查以下小说内容中的语法错误、病句、错别字、标点错误，用【原文 → 修改后】的格式列出所有问题并给出修改建议。如果没有错误，请明确说明：

原文：
${chapterContent.slice(-1500)}

检查结果（格式示例）：
1. 【"他快速的跑过来" → "他快速地跑过来"】错别字+病句
2. 【"小明和小华是好朋友，他们经常一起玩" → "小明和小华是好朋友，他们经常一起玩耍"】用词更准确` as string

      await aiModelService.stream(
        'logic',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`检查失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('语法检查失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 大纲生成 ─────────────────────────────────────────────────────────────
  const [outlineMode, setOutlineMode] = useState<'chapter' | 'full'>('chapter')

  const handleGenerateOutline = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('outline')
    setGenerating(true)
    setResult('')

    try {
      if (outlineMode === 'chapter') {
        const fullPrompt = `请分析以下章节内容，生成该章节的详细写作大纲，包括：
1. 本章核心事件
2. 主要情节点（按顺序列出）
3. 角色出场安排
4. 高潮和转折点
5. 伏笔铺设（如有）

章节内容：
${chapterContent}

章节大纲（格式清晰）：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`大纲生成失败：${error}`); setGenerating(false); }
        )
      } else {
        const fullPrompt = `请根据以下已知章节内容，为这本小说生成整体大纲框架（包括：
- 主线剧情概述
- 主要角色弧光
- 关键情节点（起承转合）
- 世界观核心设定
- 伏笔和悬念布局

已有章节内容：
${chapterContent.slice(0, 3000)}

整体大纲框架：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`大纲生成失败：${error}`); setGenerating(false); }
        )
      }
    } catch (error) {
      message.error('大纲生成失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 风格迁移 ─────────────────────────────────────────────────────────────
  const [selectedStyle, setSelectedStyle] = useState<string>('')
  const [styleStrength, setStyleStrength] = useState<number>(80)

  const handleStyleTransfer = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!selectedStyle) {
      message.warning('请选择目标风格')
      return
    }
    setActiveTool('style')
    setGenerating(true)
    setResult('')

    try {
      const styleInfo = STYLE_OPTIONS.find(s => s.value === selectedStyle)
      const strengthDesc = styleStrength > 80 ? '强烈' : styleStrength > 50 ? '中等' : '轻微'
      const fullPrompt = `请用"${styleInfo?.label}"的风格重写以下小说内容。保持情节不变，但采用该作家特有的叙事风格、文笔特点。风格强度：${strengthDesc}（${styleStrength}%）。

原文：
${chapterContent.slice(-1500)}

风格迁移后的内容（直接输出）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`风格迁移失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('风格迁移失败')
    } finally {
      setGenerating(false)
    }
  }

  // 应用生成结果
  const handleApply = () => {
    if (!result) return
    Modal.confirm({
      title: '插入方式',
      content: '选择如何将生成内容插入编辑器：',
      okText: '追加到末尾',
      cancelText: '取消',
      onOk: () => {
        onInsertText(result)
        message.success('已追加到编辑器')
        setResult('')
      },
    })
  }

  // 替换全文
  const handleReplace = () => {
    if (!result) return
    Modal.confirm({
      title: '确认替换',
      content: '将使用生成的内容完全替换当前章节内容？',
      okText: '确认替换',
      okButtonProps: { danger: true },
      cancelText: '取消',
      onOk: () => {
        onInsertText(`__REPLACE__${result}`)
        message.success('已替换章节内容')
        setResult('')
      },
    })
  }

  // 将结果插入到光标位置
  const handleInsertAtCursor = () => {
    if (!result) return
    onInsertText(result)
    message.success('已插入到编辑器')
    setResult('')
  }

  const isReplacingTool = ['rewrite', 'polish', 'style', 'grammar'].includes(activeTool)

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具标签页 */}
      <div style={{ padding: '10px 16px 0', borderBottom: '1px solid #e8e8e8' }}>
        <Tabs
          activeKey={activeTool}
          onChange={(key) => {
            setActiveTool(key)
            setResult('')
            setExtractedFacts([])
          }}
          size="small"
          items={[
            {
              key: 'writing',
              label: '✏️ 写作',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      type="primary"
                      block
                      icon={<EditOutlined />}
                      onClick={handleContinue}
                      loading={generating && activeTool === 'continue'}
                      disabled={!chapterContent}
                    >
                      智能续写
                    </Button>
                    <Button
                      block
                      icon={<ExpandOutlined />}
                      onClick={handleExpand}
                      loading={generating && activeTool === 'expand'}
                      disabled={!chapterContent}
                    >
                      定向扩写
                    </Button>
                    <Button
                      block
                      icon={<SyncOutlined />}
                      onClick={handleRewrite}
                      loading={generating && activeTool === 'rewrite'}
                      disabled={!chapterContent}
                    >
                      AI重写
                    </Button>
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handlePolish}
                      loading={generating && activeTool === 'polish'}
                      disabled={!chapterContent}
                    >
                      AI润色
                    </Button>
                    <Button
                      block
                      icon={<ScissorOutlined />}
                      onClick={handleGrammarCheck}
                      loading={generating && activeTool === 'grammar'}
                      disabled={!chapterContent}
                    >
                      语法检查
                    </Button>

                    <TextArea
                      placeholder="扩写/重写要求（可选）"
                      rows={2}
                      value={prompt}
                      onChange={(e) => setPrompt(e.target.value)}
                    />
                  </Space>

                  {activeTool === 'rewrite' && (
                    <div style={{ marginTop: 8 }}>
                      <div style={{ marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: '#666' }}>重写范围：</span>
                        <Radio.Group
                          value={rewriteScope}
                          onChange={(e) => setRewriteScope(e.target.value)}
                          size="small"
                          style={{ marginLeft: 4 }}
                        >
                          <Radio.Button value="chapter">整章</Radio.Button>
                          <Radio.Button value="paragraph">段落</Radio.Button>
                        </Radio.Group>
                        {rewriteScope === 'paragraph' && (
                          <Alert
                            message="请先在编辑器中选中要重写的段落"
                            type="info"
                            style={{ marginTop: 4, fontSize: 10 }}
                            showIcon
                          />
                        )}
                      </div>
                      <div style={{ marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: '#666' }}>重写模式：</span>
                        <Radio.Group
                          value={rewriteMode}
                          onChange={(e) => setRewriteMode(e.target.value)}
                          size="small"
                          style={{ marginLeft: 4 }}
                        >
                          <Radio.Button value="concise">精简</Radio.Button>
                          <Radio.Button value="expand">扩展</Radio.Button>
                          <Radio.Button value="improve">改进</Radio.Button>
                        </Radio.Group>
                      </div>
                      <Input
                        placeholder="重写额外要求（可选）"
                        size="small"
                        value={rewritePromptText}
                        onChange={(e) => setRewritePromptText(e.target.value)}
                        style={{ width: '100%' }}
                      />
                    </div>
                  )}

                  {activeTool === 'polish' && (
                    <Alert
                      message="润色将改善文笔表达，精简冗余，但保持原意"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}

                  {activeTool === 'grammar' && (
                    <Alert
                      message="检查语法错误、病句、错别字、标点错误"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'review',
              label: '🔍 校验',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<CheckCircleOutlined />}
                      onClick={handleCheck}
                      loading={generating && activeTool === 'check'}
                      disabled={!chapterContent}
                    >
                      逻辑校验
                    </Button>
                    <Button
                      block
                      icon={<ThunderboltOutlined />}
                      onClick={handleExtract}
                      loading={generating && activeTool === 'extract'}
                      disabled={!chapterContent}
                    >
                      提取事实
                    </Button>
                  </Space>
                </div>
              ),
            },
            {
              key: 'outline',
              label: '📋 大纲',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<ProfileOutlined />}
                      onClick={() => {
                        setOutlineMode('chapter')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成本章大纲
                    </Button>
                    <Button
                      block
                      icon={<BulbOutlined />}
                      onClick={() => {
                        setOutlineMode('full')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成整体大纲
                    </Button>
                    <Divider style={{ margin: '8px 0' }} />
                    <Select
                      placeholder="选择风格"
                      value={selectedStyle || undefined}
                      onChange={setSelectedStyle}
                      options={STYLE_OPTIONS}
                      style={{ width: '100%' }}
                      allowClear
                    />
                    {selectedStyle && (
                      <div>
                        <span style={{ fontSize: 11, color: '#666' }}>风格强度：{styleStrength}%</span>
                        <Slider
                          value={styleStrength}
                          onChange={setStyleStrength}
                          min={20}
                          max={100}
                          step={10}
                          marks={{ 20: '轻', 50: '中', 80: '强', 100: '极' }}
                        />
                      </div>
                    )}
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handleStyleTransfer}
                      loading={generating && activeTool === 'style'}
                      disabled={!chapterContent || !selectedStyle}
                    >
                      风格迁移
                    </Button>
                  </Space>
                </div>
              ),
            },
          ]}
        />
      </div>

      {/* 结果显示区 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {generating ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="AI 生成中..." />
          </div>
        ) : result ? (
          <Card
            size="small"
            title="生成结果"
            extra={
              <Space>
                {extractedFacts.length > 0 && (
                  <Button
                    type="primary"
                    size="small"
                    icon={<SaveOutlined />}
                    onClick={handleSaveFacts}
                    loading={generating}
                  >
                    保存到台账
                  </Button>
                )}
                <Button type="link" size="small" onClick={handleInsertAtCursor}>
                  插入光标
                </Button>
                <Button type="link" size="small" onClick={handleApply}>
                  追加
                </Button>
                {isReplacingTool && (
                  <Button type="link" size="small" onClick={handleReplace} danger>
                    替换全文
                  </Button>
                )}
              </Space>
            }
            style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
          >
            {result}
          </Card>
        ) : (
          <div style={{ color: '#999', textAlign: 'center', padding: 40 }}>
            选择上方工具开始使用 AI 辅助创作
          </div>
        )}
      </div>
    </div>
  )
}

export default AIToolsPanel

/**
 * 应用设置页面
 * API密钥管理、模型选择、温度参数、主题切换、自动保存间隔
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Form,
  Input,
  Select,
  Slider,
  Switch,
  Button,
  Space,
  Divider,
  message,
  Alert,
  Tabs,
  Tag,
  Tooltip,
  InputNumber,
  List,
  Modal,
} from 'antd'
import {
  KeyOutlined,
  SaveOutlined,
  CheckCircleOutlined,
  CloseCircleOutlined,
  ApiOutlined,
  SettingOutlined,
  ExperimentOutlined,
} from '@ant-design/icons'

// 可用的 AI 服务
const AI_SERVICES = [
  { value: 'deepseek', label: 'DeepSeek', models: ['deepseek-chat', 'deepseek-reasoner'] },
  { value: 'doubao', label: '豆包 (Doubao)', models: ['doubao-pro', 'doubao-lite', 'doubao-mini'] },
]

// 主题选项
const THEME_OPTIONS = [
  { value: 'light', label: '浅色' },
  { value: 'dark', label: '深色' },
  { value: 'system', label: '跟随系统' },
]

interface AppSettings {
  // AI 设置
  aiServices: Record<string, { apiKey: string; model: string; temperature: number; enabled: boolean }>
  // 自动保存
  autoSaveInterval: number // 秒
  autoSaveEnabled: boolean
  // 外观
  theme: string
  editorFontSize: number
  editorLineHeight: number
}

const DEFAULT_SETTINGS: AppSettings = {
  aiServices: {
    deepseek: { apiKey: '', model: 'deepseek-chat', temperature: 0.7, enabled: true },
    doubao: { apiKey: '', model: 'doubao-pro', temperature: 0.8, enabled: false },
  },
  autoSaveInterval: 5,
  autoSaveEnabled: true,
  theme: 'light',
  editorFontSize: 16,
  editorLineHeight: 1.8,
}

const AppSettingsPage: React.FC = () => {
  const [form] = Form.useForm<AppSettings>()
  const [saving, setSaving] = useState(false)
  const [testingService, setTestingService] = useState<string | null>(null)
  const [testResult, setTestResult] = useState<Record<string, boolean>>({})

  // 加载设置
  const loadSettings = async () => {
    try {
      const result = await window.electronAPI.ai.getSetting('appSettings', DEFAULT_SETTINGS)
      if (result.success && result.value) {
        form.setFieldsValue(result.value as AppSettings)
      } else {
        form.setFieldsValue(DEFAULT_SETTINGS)
      }
    } catch (error) {
      form.setFieldsValue(DEFAULT_SETTINGS)
    }
  }

  useEffect(() => {
    loadSettings()
  }, [])

  // 保存设置
  const handleSave = async () => {
    try {
      const values = form.getFieldsValue()
      setSaving(true)

      // 检查是否有 API key 需要加密保存
      for (const [service, config] of Object.entries(values.aiServices || {})) {
        if (config.apiKey && !config.apiKey.startsWith('encrypted:')) {
          // 加密保存
          try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const encFn = window.electronAPI.safeStorage.encrypt as (text: string) => Promise<{ success: boolean; data?: Uint8Array; error?: string }>
            const encResult = await encFn(config.apiKey)
            if (encResult.success && encResult.data) {
              // 将 Uint8Array 转为 base64 字符串存储
              const base64 = btoa(String.fromCharCode(...encResult.data))
              values.aiServices[service].apiKey = `encrypted:${base64}`
            }
          } catch (e) {
            console.warn('API key 加密失败，将以明文保存（不推荐）:', e)
            message.warning('API key 加密失败，已以明文保存（请注意安全）')
          }
        }
      }

      await window.electronAPI.ai.saveSetting('appSettings', values)
      message.success('设置已保存')
    } catch (error) {
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  // 测试连接
  const handleTestConnection = async (service: string) => {
    setTestingService(service)
    setTestResult(prev => ({ ...prev, [service]: false }))
    try {
      const result = await window.electronAPI.ai.testConnection(service)
      setTestResult(prev => ({ ...prev, [service]: !!(result.success && result.result) }))
      if (result.success && result.result) {
        message.success(`${service} 连接成功`)
      } else {
        message.error(`${service} 连接失败: ${result.error || '未知错误'}`)
      }
    } catch (error) {
      setTestResult(prev => ({ ...prev, [service]: false }))
      message.error(`${service} 连接失败`)
    } finally {
      setTestingService(null)
    }
  }

  // 验证 API Key 格式（解密显示）
  const getDisplayApiKey = (apiKey: string) => {
    if (!apiKey) return ''
    if (apiKey.startsWith('encrypted:')) {
      return '••••••••（已加密）'
    }
    if (apiKey.length > 8) {
      return apiKey.slice(0, 4) + '••••••••' + apiKey.slice(-4)
    }
    return apiKey
  }

  const values = form.getFieldsValue()

  return (
    <div
      style={{
        maxWidth: 800,
        margin: '0 auto',
        padding: 24,
        overflow: 'auto',
        height: '100%',
      }}
    >
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: 24,
        }}
      >
        <h2 style={{ margin: 0 }}>⚙️ 应用设置</h2>
        <Button
          type="primary"
          icon={<SaveOutlined />}
          loading={saving}
          onClick={handleSave}
        >
          保存设置
        </Button>
      </div>

      <Form
        form={form}
        layout="vertical"
        initialValues={DEFAULT_SETTINGS}
      >
        <Tabs
          items={[
            {
              key: 'ai',
              label: <span><ApiOutlined /> AI 服务</span>,
              children: (
                <div>
                  {AI_SERVICES.map(service => (
                    <Card
                      key={service.value}
                      size="small"
                      title={
                        <Space>
                          {service.label}
                          <Tag color={values.aiServices?.[service.value]?.enabled ? 'green' : 'default'}>
                            {values.aiServices?.[service.value]?.enabled ? '已启用' : '未启用'}
                          </Tag>
                        </Space>
                      }
                      style={{ marginBottom: 16 }}
                      extra={
                        <Switch
                          checked={values.aiServices?.[service.value]?.enabled}
                          onChange={(checked) => {
                            const current = form.getFieldValue(['aiServices', service.value]) || {}
                            form.setFieldsValue({
                              aiServices: {
                                [service.value]: { ...current, enabled: checked },
                              },
                            })
                          }}
                        />
                      }
                    >
                      <Form.Item
                        label="API Key"
                        name={['aiServices', service.value, 'apiKey']}
                        extra={
                          values.aiServices?.[service.value]?.apiKey && (
                            <Tag style={{ marginTop: 4 }}>
                              {getDisplayApiKey(values.aiServices?.[service.value]?.apiKey || '')}
                            </Tag>
                          )
                        }
                      >
                        <Input.Password
                          placeholder={
                            service.value === 'deepseek'
                              ? 'sk-xxxxxxxxxxxxxxxx'
                              : '输入 API Key'
                          }
                        />
                      </Form.Item>

                      <Form.Item
                        label="模型"
                        name={['aiServices', service.value, 'model']}
                      >
                        <Select
                          options={service.models.map(m => ({ value: m, label: m }))}
                          style={{ width: 200 }}
                        />
                      </Form.Item>

                      <Form.Item
                        label={
                          <Tooltip title="Temperature 控制创造性：0.0-0.3 更确定性，0.7-1.0 更有创意">
                            Temperature（创造性）
                          </Tooltip>
                        }
                        name={['aiServices', service.value, 'temperature']}
                      >
                        <Slider
                          min={0}
                          max={1}
                          step={0.1}
                          marks={{
                            0: '精准',
                            0.5: '平衡',
                            1: '创意',
                          }}
                          style={{ width: 300 }}
                        />
                      </Form.Item>

                      <Button
                        size="small"
                        icon={
                          testResult[service.value] ? (
                            <CheckCircleOutlined style={{ color: '#52c41a' }} />
                          ) : testResult[service.value] === false ? (
                            <CloseCircleOutlined style={{ color: '#ff4d4f' }} />
                          ) : undefined
                        }
                        onClick={() => handleTestConnection(service.value)}
                        loading={testingService === service.value}
                      >
                        测试连接
                      </Button>
                    </Card>
                  ))}

                  <Alert
                    message="API Key 安全说明"
                    description="API Key 将使用系统安全存储（SafeStorage）加密保存，不会以明文形式存储在配置文件中。"
                    type="info"
                    showIcon
                  />
                </div>
              ),
            },
            {
              key: 'editor',
              label: <span><ExperimentOutlined /> 编辑器</span>,
              children: (
                <div>
                  <Card size="small" title="自动保存" style={{ marginBottom: 16 }}>
                    <Form.Item
                      label="启用自动保存"
                      name="autoSaveEnabled"
                      valuePropName="checked"
                    >
                      <Switch />
                    </Form.Item>

                    <Form.Item
                      label="自动保存间隔（秒）"
                      name="autoSaveInterval"
                    >
                      <Slider
                        min={1}
                        max={30}
                        marks={{ 3: '3秒', 5: '5秒', 10: '10秒', 30: '30秒' }}
                        disabled={!values.autoSaveEnabled}
                      />
                    </Form.Item>
                  </Card>

                  <Card size="small" title="编辑器外观">
                    <Form.Item
                      label="字体大小"
                      name="editorFontSize"
                    >
                      <Slider
                        min={12}
                        max={24}
                        marks={{ 14: '14', 16: '16', 18: '18', 20: '20' }}
                      />
                    </Form.Item>

                    <Form.Item
                      label="行高"
                      name="editorLineHeight"
                    >
                      <Slider
                        min={1.2}
                        max={2.5}
                        step={0.1}
